// 해커스 실전 1000제 2 LC Test1
window.HK2_LC1 = {"q12": [{"n": 1, "part": 1, "q": "", "qko": "", "opts": ["She's removing her glasses.", "She's looking at a laptop.", "She's writing on a piece of paper.", "She's clearing off a table."], "optko": ["그녀는 안경을 벗고 있다.", "그녀는 노트북 컴퓨터를 보고 있다.", "그녀는 종이에 적고 있다.", "그녀는 탁자를 치우고 있다."], "ans": 1, "audio": "Test01_01.mp3", "img": "hk2_t1_q1.jpg"}, {"n": 2, "part": 1, "q": "", "qko": "", "opts": ["The man is shoveling some snow.", "The man is closing a car hood.", "A vehicle is being parked.", "A tire is being replaced."], "optko": ["남자가 눈을 삽으로 퍼내고 있다.", "남자가 자동차 보닛을 닫고 있다.", "차량이 주차되고 있다.", "타이어가 교체되고 있다."], "ans": 0, "audio": "Test01_02.mp3", "img": "hk2_t1_q2.jpg"}, {"n": 3, "part": 1, "q": "", "qko": "", "opts": ["Some people have placed notepads on a table.", "Some people are raising their hands.", "Some people are seated in a circle.", "Some people are rearranging furniture."], "optko": ["몇몇 사람들이 탁자 위에 메모지를 두었다.", "몇몇 사람들이 손을 들고 있다.", "몇몇 사람들이 원을 이루어 앉아 있다.", "몇몇 사람들이 가구를 재배치하고 있다."], "ans": 2, "audio": "Test01_03.mp3", "img": "hk2_t1_q3.jpg"}, {"n": 4, "part": 1, "q": "", "qko": "", "opts": ["The man is playing a violin.", "The woman is showing the man an instrument.", "A lamp is shining light toward some people.", "Some wood is being carved."], "optko": ["남자가 바이올린을 연주하고 있다.", "여자가 남자에게 악기를 보여주고 있다.", "전등이 몇몇 사람들 쪽으로 빛을 비추고 있다.", "목재가 조각되고 있다."], "ans": 1, "audio": "Test01_04.mp3", "img": "hk2_t1_q4.jpg"}, {"n": 5, "part": 1, "q": "", "qko": "", "opts": ["The office is being cleaned.", "Chairs are stacked in a work area.", "A curtain is covering a window.", "Desks are lined up in rows."], "optko": ["사무실이 청소되고 있다.", "의자들이 작업 공간에 쌓여 있다.", "커튼이 창문을 가리고 있다.", "책상들이 줄지어 배열되어 있다."], "ans": 3, "audio": "Test01_05.mp3", "img": "hk2_t1_q5.jpg"}, {"n": 6, "part": 1, "q": "", "qko": "", "opts": ["Pedestrians are walking across a bridge.", "Cars are parked beside a road.", "Traffic cones are positioned on a street.", "Vendor stalls are set up in a market."], "optko": ["보행자들이 다리를 걸어서 건너고 있다.", "차들이 도로 옆에 주차되어 있다.", "원뿔형의 교통 표지들이 도로 위에 놓여 있다.", "노점 가판대들이 시장에 세워져 있다."], "ans": 2, "audio": "Test01_06.mp3", "img": "hk2_t1_q6.jpg"}, {"n": 7, "part": 2, "q": "Where is this shipment of printer paper going?", "qko": "이 프린터 용지의 수송품은 어디로 가나요?", "opts": ["Ship it by today.", "A local school.", "To shop at a store."], "optko": ["오늘까지 보내주세요.", "지역 학교요.", "가게에서 쇼핑하기 위해서요."], "ans": 1, "audio": "Test01_07.mp3"}, {"n": 8, "part": 2, "q": "When do you need the sales analysis?", "qko": "매출 분석 결과가 언제 필요한가요?", "opts": ["Yes, I did.", "Sales have gone up considerably.", "By the end of the workday."], "optko": ["네, 제가 했어요.", "매출이 상당히 증가했어요.", "근무 시간이 끝나기 전까지요."], "ans": 2, "audio": "Test01_08.mp3"}, {"n": 9, "part": 2, "q": "Who signed up for tomorrow's workshop?", "qko": "내일 워크숍에 누가 신청했나요?", "opts": ["From 10 A.M. to noon.", "As long as it works properly.", "Everyone in my department."], "optko": ["오전 10시부터 정오까지요.", "제대로 작동하기만 하면요.", "제 부서의 모든 사람이요."], "ans": 2, "audio": "Test01_09.mp3"}, {"n": 10, "part": 2, "q": "Could you ask the staff to gather in the lobby in 15 minutes?", "qko": "직원들에게 15분 후에 로비로 모이라고 요청해주시겠어요?", "opts": ["Sure, they'll be able to lift it.", "I'll make an announcement.", "An hour after it started."], "optko": ["그럼요, 그들은 그것을 들 수 있을 거예요.", "제가 공지할게요.", "그것이 시작한 지 한 시간 뒤에요."], "ans": 1, "audio": "Test01_10.mp3"}, {"n": 11, "part": 2, "q": "Why can't gym members use the pool right now?", "qko": "왜 체육관 회원들은 수영장을 지금 사용할 수 없나요?", "opts": ["It's being cleaned.", "Swimming is a great exercise.", "Because she's a member."], "optko": ["청소되고 있어요.", "수영은 좋은 운동이에요.", "그녀가 회원이기 때문이에요."], "ans": 0, "audio": "Test01_11.mp3"}, {"n": 12, "part": 2, "q": "Should we consult with a lawyer before signing the contract?", "qko": "우리는 계약서에 서명을 하기 전에 변호사와 상의해야 할까요?", "opts": ["Yes, I think so.", "Did he sign the agreement?", "I received his autograph too."], "optko": ["네, 저는 그렇게 생각해요.", "그가 계약서에 서명했나요?", "저도 그의 사인을 받았어요."], "ans": 0, "audio": "Test01_12.mp3"}, {"n": 13, "part": 2, "q": "What's the name of the neighborhood where Neil will be moving to in November?", "qko": "Neil이 11월에 이사를 가게 될 동네의 이름이 무엇인가요?", "opts": ["This area gets quite busy.", "Maybe Susan remembers.", "The product hasn't been named yet."], "optko": ["이 지역은 꽤 혼잡해져요.", "아마 Susan이 기억할 거예요.", "제품에 아직 이름을 붙이지 않았어요."], "ans": 1, "audio": "Test01_13.mp3"}, {"n": 14, "part": 2, "q": "How far does this beach extend?", "qko": "이 해변은 얼마나 멀리 펼쳐지나요?", "opts": ["About half a mile or so.", "No, I've never visited this beach.", "Let's put on our sunglasses."], "optko": ["약 반 마일 정도요.", "아니요, 저는 이 해변에 와본 적이 없어요.", "선글라스를 씁시다."], "ans": 0, "audio": "Test01_14.mp3"}, {"n": 15, "part": 2, "q": "Have all the clients taken their seats?", "qko": "모든 고객들이 자리에 앉았나요?", "opts": ["Each has been installed.", "A few still haven't arrived.", "My seat is over there."], "optko": ["각각 설치되었어요.", "아직 몇 분이 도착하지 않았어요.", "제 자리는 저쪽이에요."], "ans": 1, "audio": "Test01_15.mp3"}, {"n": 16, "part": 2, "q": "Why did you switch the brown sweater for another one?", "qko": "왜 갈색 스웨터를 다른 것으로 바꾸었나요?", "opts": ["Then we'll find another location.", "It was too small for me.", "Brown is my favorite color."], "optko": ["그럼 우리는 다른 장소를 찾을 거예요.", "저에게 너무 작았어요.", "갈색은 제가 가장 좋아하는 색이에요."], "ans": 1, "audio": "Test01_16.mp3"}, {"n": 17, "part": 2, "q": "Should beverages be served at 5 P.M., or should we wait until after the performance?", "qko": "음료가 오후 5시에 제공되어야 할까요, 아니면 공연이 끝날 때까지 기다려야 할까요?", "opts": ["Earlier would be better.", "Our waiter is very friendly.", "We should make a donation."], "optko": ["더 빠른 것이 나을 것 같아요.", "우리의 웨이터는 굉장히 친절해요.", "우리는 기부를 해야 해요."], "ans": 0, "audio": "Test01_17.mp3"}, {"n": 18, "part": 2, "q": "You already watched our training video, didn't you?", "qko": "당신은 우리의 교육 영상을 이미 봤죠, 그렇지 않나요?", "opts": ["That train already departed.", "Yes, I'm enjoying the job.", "About a month ago."], "optko": ["그 기차는 이미 출발했어요.", "네, 저는 일을 즐기고 있어요.", "한 달 전쯤에요."], "ans": 2, "audio": "Test01_18.mp3"}, {"n": 19, "part": 2, "q": "Where did you work before this?", "qko": "이곳 전에 어디에서 일을 하셨어요?", "opts": ["See you after the show.", "I interned at a laboratory.", "From some corporate leaders."], "optko": ["공연이 끝나고 만나요.", "실험실에서 인턴으로 근무했어요.", "회사 지도자들로부터요."], "ans": 1, "audio": "Test01_19.mp3"}, {"n": 20, "part": 2, "q": "Is $500 too much for this painting, or is it a fair price?", "qko": "이 그림에 500달러는 과한가요, 아니면 적정한 가격인가요?", "opts": ["I'll check the receipt.", "You're going to love the museum.", "That seems overpriced."], "optko": ["영수증을 확인할게요.", "당신은 이 미술관을 정말 좋아하실 거예요.", "그것은 값이 너무 비싸게 매겨진 것 같네요."], "ans": 2, "audio": "Test01_20.mp3"}, {"n": 21, "part": 2, "q": "Does the pamphlet you're making for our company explain our ongoing projects?", "qko": "당신이 우리 회사를 위해 만들고 있는 소책자는 우리의 진행 중인 프로젝트들에 대해 설명하나요?", "opts": ["Yes, but it's not my container.", "I made sure to include that information.", "Most of the brochures can be recycled."], "optko": ["네, 하지만 그것은 제 용기가 아니에요.", "저는 그 정보를 확실히 포함시켰어요.", "대부분의 소책자들은 재활용할 수 있어요."], "ans": 1, "audio": "Test01_21.mp3"}, {"n": 22, "part": 2, "q": "Are you satisfied with your raise?", "qko": "당신의 임금 인상에 대해 만족하시나요?", "opts": ["Yes, I really appreciate it.", "It'd be nice to increase productivity.", "They were sent to the payroll department."], "optko": ["네, 저는 그것에 대해 정말 감사해요.", "생산성을 높이면 좋을 것 같아요.", "그것들은 급여 지급 부서로 보내졌어요."], "ans": 0, "audio": "Test01_22.mp3"}, {"n": 23, "part": 2, "q": "Didn't you see the warehouse when you were shown around our facility?", "qko": "저희 시설을 둘러보도록 안내받으셨을 때 창고를 보지 못하셨나요?", "opts": ["I was told we had to skip it.", "Let's store those goods too.", "Both tour times work for me."], "optko": ["저는 우리가 그것을 건너뛰어야 한다고 들었어요.", "그 상품들도 보관합시다.", "두 견학 시간대 모두 저에게 괜찮아요."], "ans": 0, "audio": "Test01_23.mp3"}, {"n": 24, "part": 2, "q": "I had a difficulty logging in to the wireless network.", "qko": "저는 무선 네트워크에 로그인하는 데 어려움을 겪었어요.", "opts": ["I couldn't find the venue either.", "It's been unreliable lately.", "Thanks for solving the problem."], "optko": ["저도 그 장소를 찾지 못했어요.", "최근 들어 신뢰할 수 없어요.", "문제를 해결해주셔서 감사해요."], "ans": 1, "audio": "Test01_24.mp3"}, {"n": 25, "part": 2, "q": "Would you like to borrow my phone charger?", "qko": "제 핸드폰 충전기를 빌려드릴까요?", "opts": ["Try dialing the number again.", "When did you lend them to Paul?", "Sure. I'll give it back soon."], "optko": ["다시 전화를 걸어보세요.", "그것들을 Paul에게 언제 빌려주었나요?", "그럼요. 곧 그것을 돌려드릴게요."], "ans": 2, "audio": "Test01_25.mp3"}, {"n": 26, "part": 2, "q": "How many rehearsals are left before the first performance?", "qko": "첫 공연을 앞두고 몇 번의 리허설이 남아 있나요?", "opts": ["The car performed well.", "We're looking forward to the play.", "This is the second-to-last."], "optko": ["그 차는 잘 작동했어요.", "저희는 그 연극을 기대하고 있어요.", "이번이 끝에서 두 번째예요."], "ans": 2, "audio": "Test01_26.mp3"}, {"n": 27, "part": 2, "q": "I'm wondering which hotel to book for the holidays.", "qko": "휴가를 위해 어떤 호텔을 예약해야 할지 모르겠어요.", "opts": ["Reservations can be confirmed online.", "Valley Inn has an indoor pool.", "Throughout the entire weekend."], "optko": ["예약은 온라인에서 확인할 수 있어요.", "Valley 호텔은 실내 수영장이 있어요.", "주말 동안 내내요."], "ans": 1, "audio": "Test01_27.mp3"}, {"n": 28, "part": 2, "q": "We should conduct a focus group on our new laptop, shouldn't we?", "qko": "우리는 새 노트북 컴퓨터에 대한 포커스 그룹을 실시해야 해요, 그렇지 않나요?", "opts": ["Since the company grew larger.", "I doubt we have the funds to do that.", "Yes, most of the participants."], "optko": ["회사가 더 커진 이후로요.", "우리가 그것을 할 자금이 있는지 의문이네요.", "네, 대부분의 참가자들이요."], "ans": 1, "audio": "Test01_28.mp3"}, {"n": 29, "part": 2, "q": "The chef prepared this complimentary dessert for you.", "qko": "주방장이 당신을 위해 이 무료 후식을 준비했어요.", "opts": ["I'm well prepared for the interview.", "Tell them it will be served soon.", "Wow. It looks delicious."], "optko": ["저는 그 인터뷰에 대해 준비가 잘 되어 있어요.", "그들에게 그것이 곧 제공될 것이라고 말해주세요.", "우와. 정말 맛있어 보여요."], "ans": 2, "audio": "Test01_29.mp3"}, {"n": 30, "part": 2, "q": "Are there any rental cars available that can fit six people?", "qko": "여섯 명이 탈 수 있는 임대 자동차가 있나요?", "opts": ["This SUV can accommodate seven passengers.", "Customers are charged extra for gas.", "Many drivers find the congestion frustrating."], "optko": ["이 SUV는 일곱 명의 승객을 수용할 수 있어요.", "고객들에게 휘발유 요금이 추가로 부과돼요.", "많은 운전자들은 교통 정체에 불만스러워해요."], "ans": 0, "audio": "Test01_30.mp3"}, {"n": 31, "part": 2, "q": "For $50 more, I can give you an extended warranty.", "qko": "50달러를 더 지불하시면, 품질 보증 연장을 해드릴 수 있어요.", "opts": ["There are fewer models than expected.", "Great. I'll be sure to delete it.", "OK. Charge it all to my credit card."], "optko": ["예상했던 것보다 모델이 더 적네요.", "좋아요. 제가 확실히 그것을 삭제할게요.", "알겠어요. 모두 제 신용카드로 청구해 주세요."], "ans": 2, "audio": "Test01_31.mp3"}], "sets34": [{"start": 32, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 캐나다식 발음", "audio": "Test01_32-34.mp3", "qs": [{"n": 32, "q": "What will the man do next week?", "opts": ["Take a business trip", "Meet with a company president", "Make an international call", "Apply for a credit card"], "ans": 0, "ko": "남자는 다음 주에 무엇을 할 것인가?"}, {"n": 33, "q": "Which department does the man most likely work in?", "opts": ["Marketing", "Sales", "Legal", "Accounting"], "ans": 2, "ko": "남자는 어느 부서에서 일하는 것 같은가?"}, {"n": 34, "q": "What does the woman advise the man to do?", "opts": ["Update a directory", "Visit a Web site", "Request a refund", "Contact another department"], "ans": 1, "ko": "여자는 남자에게 무엇을 하라고 조언하는가?"}], "script": [{"sp": "W", "en": "Hi, Mark. I heard you were asked to travel with the marketing and sales team members to Tokyo next week.", "ko": "안녕하세요, Mark. 저는 당신이 다음 주에 마케팅팀과 영업팀 직원들과 함께 도쿄에 가도록 요청받았다고 들었어요."}, {"sp": "M", "en": "That's right. Our CEO thinks we may have to make a few last-minute changes to the contract with the local company that will distribute our products. So, he wants someone from the legal department to go along. Oh, that reminds me . . . I paid for my flight and hotel with my personal credit card. Do you know where I can get information about the reimbursement process?", "ko": "맞아요. 우리 최고 경영자는 우리의 제품들을 유통시킬 지역 회사와의 계약에 약간의 막바지 변경을 해야 할 수도 있다고 생각해요. 그래서 그는 법무 부서의 누군가가 동행하기를 원해요. 아, 그러고 보니 생각나네요… 저는 제 개인 신용 카드로 제 항공편과 호텔비를 지불했어요. 제가 상환 절차에 대한 정보를 어디에서 얻을 수 있는지 알고 계세요?"}, {"sp": "W", "en": "You should read the guide posted on the company intranet by the accounting team. It includes detailed instructions.", "ko": "당신은 회계팀이 회사 내부 전산망에 게시한 안내서를 읽어보셔야 해요. 상세한 설명이 포함되어 있어요."}, {"sp": "M", "en": "Thanks. I'll do that right away.", "ko": "감사해요. 바로 그렇게 할게요."}]}, {"start": 35, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 영국식 발음", "audio": "Test01_35-37.mp3", "qs": [{"n": 35, "q": "Where is the conversation most likely taking place?", "opts": ["In a theater", "In a department store", "In a hotel", "In a government office"], "ans": 0, "ko": "대화는 어디에서 일어나고 있는 것 같은가?"}, {"n": 36, "q": "What does the woman ask for?", "opts": ["A description of an item", "The name of an owner", "The date of a visit", "A confirmation of a payment"], "ans": 0, "ko": "여자는 무엇을 요청하는가?"}, {"n": 37, "q": "What will the man most likely do next?", "opts": ["Make a payment", "Show an identification card", "Pose for a photograph", "Fill out an application form"], "ans": 1, "ko": "남자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "M", "en": "Excuse me. I watched a play here on May 19, and I believe I left my watch in the bathroom. I took it off when I was washing my hands. Has anyone turned one in?", "ko": "실례합니다. 저는 5월 19일에 여기에서 연극을 봤는데, 화장실에 제 시계를 놓고 간 것 같아요. 제가 손을 씻을 때 그것을 벗어 놓았거든요. 그걸 돌려준 사람이 있나요?"}, {"sp": "W", "en": "Actually, yes. But I need to confirm that you are the owner. Um, could you tell me what your watch looks like?", "ko": "사실, 있었어요. 하지만 저는 당신이 주인인지 확인해야 해요. 음, 당신의 시계가 어떻게 생겼는지 말씀해주실 수 있나요?"}, {"sp": "M", "en": "Sure. It has a steel case and a leather strap. And, uh, if you look at the back, you will see that my name is inscribed . . . um, James Higgs.", "ko": "그럼요. 그것은 철제 케이스와 가죽끈이 있어요. 그리고, 어, 뒤를 보시면, 제 이름이 새겨져 있는 것이 보이실 거예요… 음, James Higgs요."}, {"sp": "W", "en": "Well, Mr. Higgs, you are in luck! If I can just see your driver's license or another piece of photo ID, I can give you your watch back.", "ko": "음, Mr. Higgs, 운이 좋으시네요! 제가 당신의 운전면허증이나 사진이 부착된 다른 신분증을 볼 수 있다면, 시계를 당신에게 돌려드릴 수 있습니다."}]}, {"start": 38, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test01_38-40.mp3", "qs": [{"n": 38, "q": "What problem does the man mention?", "opts": ["A conference was canceled.", "A device is malfunctioning.", "A presentation was postponed.", "A technician is out sick."], "ans": 1, "ko": "남자는 무슨 문제를 언급하는가?"}, {"n": 39, "q": "When is the man supposed to meet with a manager?", "opts": ["At 2:00 P.M.", "At 2:30 P.M.", "At 3:00 P.M.", "At 3:30 P.M."], "ans": 0, "ko": "남자는 언제 관리자와 만나기로 되어 있는가?"}, {"n": 40, "q": "What does the woman recommend?", "opts": ["Attending a workshop", "Changing a schedule", "Testing a projector", "Reserving a space"], "ans": 3, "ko": "여자는 무엇을 제안하는가?"}], "script": [{"sp": "M", "en": "Sarah, the projector in the conference room doesn't seem to be working. Could you call a technician?", "ko": "Sarah, 회의실에 있는 프로젝터가 작동하지 않는 것 같아요. 기술자를 불러줄 수 있나요?"}, {"sp": "W", "en": "I already did . . . Someone from the tech team will be here at 3 or 3:30 P.M.", "ko": "이미 했어요… 기술팀의 누군가가 오후 3시나 3시 30분에 여기로 올 거예요."}, {"sp": "M", "en": "But I have to give a presentation to our department head at 2. Is there any way a technician could come earlier?", "ko": "하지만 저는 2시에 우리 부장님께 발표를 해야 해요. 기술자가 더 일찍 올 수 있는 방법이 있을까요?"}, {"sp": "W", "en": "I don't think so . . . That team is really busy today.", "ko": "없을 것 같아요… 그 팀은 오늘 정말 바빠요."}, {"sp": "M", "en": "I'm not sure what to do, then. All the other rooms are booked.", "ko": "그럼 제가 무엇을 해야 할지 모르겠네요. 다른 모든 회의실은 예약이 되어 있어요."}, {"sp": "W", "en": "Um, I think the one on the second floor might be available at that time. The workshop that was going to be held there was rescheduled. You should book it right away, though.", "ko": "음, 2층의 회의실 하나가 그때 이용 가능할 수도 있어요. 그곳에서 열리기로 되어 있던 워크숍 일정이 변경되었거든요. 그래도 당신은 지금 바로 그것을 예약해야 해요."}]}, {"start": 41, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음 → 영국식 발음", "audio": "Test01_41-43.mp3", "qs": [{"n": 41, "q": "What will begin at 4 P.M.?", "opts": ["A social gathering", "A private consultation", "A training session", "A cooking class"], "ans": 0, "ko": "오후 4시에 무엇이 시작될 것인가?"}, {"n": 42, "q": "Why did the women arrive early?", "opts": ["To sample some dishes", "To volunteer their services", "To make revisions to a plan", "To rehearse some music"], "ans": 1, "ko": "여자들은 왜 일찍 도착했는가?"}, {"n": 43, "q": "What does the man ask the women to do?", "opts": ["Clean up a space", "Stop by a market", "Cut up some produce", "Move some tables"], "ans": 2, "ko": "남자는 여자들에게 무엇을 해달라고 요청하는가?"}], "script": [{"sp": "M", "en": "Elena, Patricia! It's so nice to see you both. You're a bit early, though. Dan's birthday party doesn't officially begin until 4 P.M.", "ko": "Elena, Patricia! 두 분 모두를 보게 되어 정말 반가워요. 그런데, 조금 일찍 오셨네요. Dan의 생일 파티는 오후 4시나 되어야 정식으로 시작할 거예요."}, {"sp": "W1", "en": "We know it's only 3 o'clock, but we thought we would come a bit early to lend a hand.", "ko": "저희는 이제 겨우 3시인 것을 알지만, 도와드리려고 조금 일찍 와야겠다고 생각했어요."}, {"sp": "W2", "en": "Yeah. We figured you might need some help preparing food and decorating. Hopefully, we're not intruding.", "ko": "맞아요. 저희는 당신이 음식을 준비하고 장식하는 데에 도움이 필요할 수 있을 거라고 생각했어요. 바라건대, 저희가 방해하는 것이 아니면 좋겠네요."}, {"sp": "M", "en": "Not at all! In fact, I'm glad you're here. I'm running a bit behind, so this is great.", "ko": "전혀 아니에요! 사실, 여러분이 오셔서 기뻐요. 저는 조금 늦어지고 있어서, 정말 잘 됐어요."}, {"sp": "W2", "en": "Well, what can we do?", "ko": "음, 저희가 무엇을 할 수 있을까요?"}, {"sp": "M", "en": "Why don't you two chop up the tomatoes and onions in the kitchen for fresh salsa? While you do that, I'll set the table.", "ko": "두 분이 주방에서 신선한 살사를 위한 토마토와 양파를 잘게 썰어주시는 게 어때요? 그것을 하실 동안, 저는 식탁을 차릴게요."}]}, {"start": 44, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 호주식 발음", "audio": "Test01_44-46.mp3", "qs": [{"n": 44, "q": "Where most likely are the speakers?", "opts": ["At a theater", "At a restaurant", "At a shopping complex", "At a stadium"], "ans": 3, "ko": "화자들은 어디에 있는 것 같은가?"}, {"n": 45, "q": "What is mentioned about the man's coworker?", "opts": ["He invited some friends over.", "He is able to attend an event.", "He is a season ticket holder.", "He worked an extra shift."], "ans": 2, "ko": "남자의 직장 동료에 관해 무엇이 언급되는가?"}, {"n": 46, "q": "Why does the man say, \"I've got a hot dog and soda\"?", "opts": ["To calculate an amount", "To point out a mistake", "To indicate a preference", "To turn down an offer"], "ans": 3, "ko": "남자는 왜 \"저는 핫도그와 탄산음료가 있어요\"라고 말하는가?"}], "script": [{"sp": "W", "en": "Thanks for inviting me today. The Stallions are my favorite baseball team, but I rarely get a chance to go to their games. This is a lot of fun.", "ko": "오늘 저를 초대해주셔서 감사해요. The Stallions는 제가 가장 좋아하는 야구팀이지만, 저는 그들의 경기에 갈 기회가 거의 없거든요. 정말 재미있네요."}, {"sp": "M", "en": "My pleasure. A coworker of mine has season tickets for all of the home games. He's out of town this weekend, so he gave me his tickets.", "ko": "천만에요. 제 직장 동료가 모든 홈 경기에 대한 정기권을 가지고 있어요. 그가 이번 주말에 다른 지역으로 가게 되어서, 그의 표를 제게 주었어요."}, {"sp": "W", "en": "That was very generous of him. Well, I'm going to grab some snacks. Do you need anything?", "ko": "그분 정말 후하시네요. 음, 제가 간식을 좀 가져올게요. 뭐 필요한 것 있으세요?"}, {"sp": "M", "en": "I've got a hot dog and soda.", "ko": "저는 핫도그와 탄산음료가 있어요."}]}, {"start": 47, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test01_47-49.mp3", "qs": [{"n": 47, "q": "What type of event does the woman want flowers for?", "opts": ["A retirement celebration", "An award presentation", "A graduation ceremony", "A company outing"], "ans": 1, "ko": "여자는 어떤 종류의 행사를 위해 꽃을 원하는가?"}, {"n": 48, "q": "Why does the man apologize?", "opts": ["A delivery service is not available.", "A store has increased its prices.", "A product is not in stock.", "An order has not been prepared."], "ans": 2, "ko": "남자는 왜 사과하는가?"}, {"n": 49, "q": "What does the man recommend?", "opts": ["Browsing an online catalog", "Contacting a different branch", "Ordering another product", "Sending a gift card"], "ans": 1, "ko": "남자는 무엇을 제안하는가?"}], "script": [{"sp": "M", "en": "Bellport Florist, Gerald speaking. How can I help you today?", "ko": "Bellport 꽃집의 Gerald입니다. 오늘 어떻게 도와드릴까요?"}, {"sp": "W", "en": "I'm interested in buying flowers for a coworker. She's been selected as the employee of the month and will be presented with an award during a ceremony tomorrow morning. So, I need to pick the flowers up this afternoon.", "ko": "저는 직장 동료를 위해 꽃을 사는 것에 관심이 있어요. 그녀는 이달의 직원으로 선정되었고 내일 아침 기념식 중에 상을 수상할 거예요. 그래서, 저는 오늘 오후에 꽃을 찾으러 와야 해요."}, {"sp": "M", "en": "That shouldn't be a problem. Is there a particular kind of flower you'd like to get?", "ko": "그건 문제가 되지 않을 거예요. 구매하길 원하시는 특정한 꽃 종류가 있으세요?"}, {"sp": "W", "en": "Yes. Orchids are her favorite flower, so a bouquet of those, please.", "ko": "네. 난초가 그녀의 가장 좋아하는 꽃이라, 그것들로 꽃다발 하나를 주세요."}, {"sp": "M", "en": "Oh . . . I'm very sorry, but we ran out of those this morning. We don't expect another shipment until Saturday. However, our branch in Hereford might have some available. I suggest that you give them a call.", "ko": "아… 정말 죄송하지만, 그것들은 오늘 아침에 다 떨어졌어요. 저희는 토요일이나 되어야 또 다른 배송이 올 것으로 예상해요. 하지만, Hereford에 있는 저희 지점에는 구입할 수 있는 것이 조금 있을 거예요. 그쪽으로 전화해보시는 것을 제안드려요."}]}, {"start": 50, "part": 3, "intro": "", "graphic": false, "speakers": "캐나다식 발음 → 미국식 발음", "audio": "Test01_50-52.mp3", "qs": [{"n": 50, "q": "Where most likely are the speakers?", "opts": ["In a convention center", "In a corporate office", "In a hotel", "In a mall"], "ans": 2, "ko": "화자들은 어디에 있는 것 같은가?"}, {"n": 51, "q": "Why does the man say, \"Bently Furniture specializes in commercial furniture\"?", "opts": ["To accept an offer", "To indicate a problem", "To suggest an alternative", "To explain a decision"], "ans": 2, "ko": "남자는 왜 \"Bently 가구점은 상업용 가구를 전문으로 해요\"라고 말하는가?"}, {"n": 52, "q": "Why will the woman make a phone call?", "opts": ["To inquire about product availability", "To request a confirmation number", "To provide some feedback", "To confirm a delivery time"], "ans": 0, "ko": "여자는 왜 전화를 할 것인가?"}], "script": [{"sp": "M", "en": "I have a suggestion for decorating this lobby. Why don't we choose furniture that complements the blue and green wallpaper we have used throughout the hotel?", "ko": "저는 이 로비를 장식하는 것에 대해 제안이 있습니다. 우리가 호텔 전체에 걸쳐 사용한 파란색과 초록색 벽지를 보완해줄 가구를 고르면 어떨까요?"}, {"sp": "W", "en": "Good idea. We'll definitely need several couches. And they should be made of leather as that material is very durable. Why don't we look at some from West Loop?", "ko": "좋은 생각이네요. 확실히 여러 개의 소파가 필요할 거예요. 그리고 가죽이 내구성이 매우 좋으므로 그것들은 그 재질로 만들어져야 해요. West Loop에서 좀 찾아보는 게 어때요?"}, {"sp": "M", "en": "West Loop mostly sells items that are suitable for private residences. But, um . . . Bently Furniture specializes in commercial furniture.", "ko": "West Loop은 대부분 개인 주택에 적합한 물품들을 판매해요. 하지만, 음… Bently 가구점은 상업용 가구를 전문으로 해요."}, {"sp": "W", "en": "Yeah, I suppose so. In that case, I'll call that store to find out whether they have any leather sofas in stock.", "ko": "네, 그런 것 같네요. 그렇다면, 가죽 소파의 재고가 있는지 알아보기 위해 제가 그 가게에 전화해볼게요."}]}, {"start": 53, "part": 3, "intro": "", "graphic": false, "speakers": "미국식 발음 → 호주식 발음", "audio": "Test01_53-55.mp3", "qs": [{"n": 53, "q": "What does the man ask the woman about?", "opts": ["A departure time", "A first-class ticket", "A luggage policy", "A gate location"], "ans": 0, "ko": "남자는 여자에게 무엇에 관해 문의하는가?"}, {"n": 54, "q": "What does the man say he will do?", "opts": ["Wait for a shuttle bus", "Make some business calls", "Charge to a corporate credit card", "Accept a free upgrade"], "ans": 1, "ko": "남자는 무엇을 할 것이라고 말하는가?"}, {"n": 55, "q": "What does the woman recommend?", "opts": ["Looking at a digital board", "Using a station facility", "Paying for wireless Internet", "Following other passengers"], "ans": 1, "ko": "여자는 무엇을 제안하는가?"}], "script": [{"sp": "W", "en": "Hello, sir. How can I help you this morning?", "ko": "안녕하세요, 손님. 오늘 아침에 어떻게 도와드릴까요?"}, {"sp": "M", "en": "I need to travel to Berlin. I know a train on the Red Line regularly heads there from Bonn. When does the next one leave?", "ko": "저는 베를린으로 가야 해요. 빨간색 노선의 열차가 본에서 그곳으로 정기적으로 가는 것으로 알고 있는데요. 다음 열차는 언제 출발하나요?"}, {"sp": "W", "en": "The next one won't leave for about two hours.", "ko": "다음 열차는 두 시간 후에나 출발할 겁니다."}, {"sp": "M", "en": "I'd like a ticket for that one. I can call some of my clients while I wait.", "ko": "그 열차의 표 한 장을 주세요. 저는 기다리는 동안 제 고객들과 통화하면 돼요."}, {"sp": "W", "en": "Certainly. It'll be €75. By the way, I encourage you to make use of our lounge. It offers comfortable chairs, free wireless Internet, and vending machines. It's just down the hallway to your left.", "ko": "그럼요. 75유로 되겠습니다. 그건 그렇고, 손님께서 저희 라운지를 이용하시기를 권해드립니다. 편안한 의자, 무료 무선 인터넷, 그리고 자판기를 제공하거든요. 통로를 쭉 내려가셔서 손님의 왼쪽에 있습니다."}]}, {"start": 56, "part": 3, "intro": "", "graphic": false, "speakers": "영국식 발음 → 캐나다식 발음", "audio": "Test01_56-58.mp3", "qs": [{"n": 56, "q": "What is the report about?", "opts": ["Consumer complaints", "Production costs", "Clothing lines", "Potential markets"], "ans": 3, "ko": "보고서는 무엇에 관한 것인가?"}, {"n": 57, "q": "Who is Fred Diamond?", "opts": ["An investor", "A client", "A designer", "An intern"], "ans": 0, "ko": "Fred Diamond는 누구인가?"}, {"n": 58, "q": "What will the woman probably do next?", "opts": ["Print a handout", "Read an e-mail", "Explain a decision", "Correct a document"], "ans": 1, "ko": "여자는 다음에 무엇을 할 것 같은가?"}], "script": [{"sp": "W", "en": "I'm glad I've bumped into you. I'm wondering how the report you're working on is coming along. The one about the risk analysis of the South American consumer markets that we're considering entering.", "ko": "당신과 마주치게 되어 기쁘네요. 당신이 작업하고 있는 보고서가 어떻게 되어 가고 있는지 궁금해요. 우리가 진입하려고 고려 중인 남아메리카 소비자 시장의 위험 분석에 관한 것이요."}, {"sp": "M", "en": "I finished it two hours ago.", "ko": "저는 그것을 두 시간 전에 끝냈어요."}, {"sp": "W", "en": "Could you e-mail it to me, then? Tomorrow, I'll be meeting with Fred Diamond, a major investor in our clothing firm. He wants to discuss our plan.", "ko": "그러면, 저한테 그것을 이메일로 보내줄 수 있나요? 내일, 저는 우리 의류 회사의 주요 투자자인 Fred Diamond와 만날 예정이거든요. 그는 우리의 계획을 논의하기를 원해요."}, {"sp": "M", "en": "Actually, I already sent it. I figured you already knew.", "ko": "사실, 저는 이미 그것을 보냈어요. 저는 당신이 이미 알고 있다고 생각했어요."}, {"sp": "W", "en": "Oh, I must have overlooked that e-mail. I'll check for it again and contact you if I have questions about the report.", "ko": "아, 제가 그 이메일을 못 보고 넘어간 것 같네요. 제가 그것을 다시 확인해보고 보고서에 관해 질문이 있으면 당신에게 연락할게요."}]}, {"start": 59, "part": 3, "intro": "", "graphic": false, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test01_59-61.mp3", "qs": [{"n": 59, "q": "According to the man, what will the speakers mostly discuss?", "opts": ["An effort to hire additional teachers", "A change to voting regulations", "A city's community festivals", "A politician's professional background"], "ans": 3, "ko": "남자에 따르면, 화자들은 주로 무엇을 논의할 것인가?"}, {"n": 60, "q": "What news does the woman announce?", "opts": ["An early retirement", "A budget increase", "An award nomination", "A project delay"], "ans": 1, "ko": "여자는 어떤 소식을 발표하는가?"}, {"n": 61, "q": "What is mentioned about city schools?", "opts": ["They have highly trained staff.", "They may reduce class sizes.", "They will receive more supplies.", "They can enroll more students."], "ans": 2, "ko": "시립 학교들에 관해 무엇이 언급되는가?"}], "script": [{"sp": "M", "en": "Mayor Lamar, thank you for joining me on this episode of Happening Today. We'll spend most of the hour talking about your work as a civil rights lawyer before being elected earlier this year. However, I believe you have some news to share before we get into that.", "ko": "Lamar 시장님, Happening Today의 이번 에피소드에 저와 함께 해 주셔서 감사합니다. 저희는 대부분의 시간을 올해 초 선출되시기 전 인권 변호사로서의 성과에 대해 이야기하며 보낼 것입니다. 하지만, 그 이야기를 하기 전에 시장님께서 나누고 싶으신 소식이 있을 것 같습니다."}, {"sp": "W", "en": "Yes. I'm very pleased to announce that, after working with the city council, I've been able to secure over $5 million in additional funding for the city's schools next year. It's my first major accomplishment as the mayor of Chicago.", "ko": "네. 저는 시의회와 함께 노력한 끝에, 내년에 시립 학교들을 위한 추가 자금으로 5백만 달러 이상을 확보할 수 있게 된 것을 알려드리게 되어 매우 기쁩니다. 이것은 시카고 시장으로서 저의 첫 번째 주요 업적입니다."}, {"sp": "M", "en": "And how will the funds be used?", "ko": "그럼 그 자금은 어떻게 사용될 것인가요?"}, {"sp": "W", "en": "City schools will be getting additional books, art materials, and furniture.", "ko": "시립 학교들이 추가적인 책, 미술 재료, 가구를 받게 될 것입니다."}]}, {"start": 62, "part": 3, "intro": "", "graphic": true, "speakers": "미국식 발음 → 호주식 발음", "audio": "Test01_62-64.mp3", "qs": [{"n": 62, "q": "What type of event is taking place today?", "opts": ["A training session", "A welcoming party", "A birthday celebration", "A branch opening"], "ans": 1, "ko": "오늘 어떤 종류의 행사가 열리는가?"}, {"n": 63, "q": "Look at the graphic. Which highway exit did the man most likely take?", "opts": ["Exit 13", "Exit 14", "Exit 15", "Exit 16"], "ans": 0, "ko": "시각 자료를 보시오. 남자는 어떤 고속도로 출구로 나온 것 같은가?"}, {"n": 64, "q": "What does the man offer to do?", "opts": ["Drop off a vehicle", "Fill up a gas tank", "Pick up some beverages", "Call some suppliers"], "ans": 2, "ko": "남자는 무엇을 해주겠다고 제안하는가?"}], "script": [{"sp": "W", "en": "Paul, it's Wendy. I'm wondering how far away you are from the office. The gathering to welcome our new branch manager doesn't start for another hour, but I'd like to talk to you about the training workshop we're holding for the accounting staff next week.", "ko": "Paul, 저 Wendy예요. 당신이 사무실에서 얼마나 멀리 있는지 궁금해요. 우리의 새로운 지점 관리자를 환영하기 위한 모임이 한 시간 뒤에야 시작하지만, 다음 주에 회계 직원들을 위해 우리가 열 교육 워크숍에 대해서 당신과 이야기하고 싶어요."}, {"sp": "M", "en": "Not too far. I just pulled off the highway, and I am passing Sun Market now. I should be there in 15 minutes or so.", "ko": "그렇게 멀리 있지 않아요. 저는 막 고속도로를 빠져나왔고, 지금 Sun 마켓을 지나고 있어요. 그곳에 15분 정도면 도착해요."}, {"sp": "W", "en": "OK, great. That'll give us a chance to chat beforehand.", "ko": "알겠어요, 좋아요. 우리가 미리 이야기할 기회가 있겠네요."}, {"sp": "M", "en": "Sounds good. By the way, do you need me to get any last-minute supplies? Are there enough drinks for everyone?", "ko": "다행이에요. 그런데, 제가 최종적으로 물품들을 사갈 필요가 있나요? 모두가 마실 음료가 충분히 있나요?"}, {"sp": "W", "en": "Thanks, but that's not necessary.", "ko": "감사하지만, 필요하지 않아요."}], "gimg": "hk2_t1_g62.jpg"}, {"start": 65, "part": 3, "intro": "", "graphic": true, "speakers": "캐나다식 발음 → 영국식 발음", "audio": "Test01_65-67.mp3", "qs": [{"n": 65, "q": "According to the man, who is the device for?", "opts": ["A colleague", "A relative", "A friend", "A client"], "ans": 1, "ko": "남자에 따르면, 기기는 누구를 위한 것인가?"}, {"n": 66, "q": "What feature does the man want to prioritize?", "opts": ["Portability", "Battery life", "Affordability", "Display size"], "ans": 3, "ko": "남자는 어떤 특징을 우선시하기를 원하는가?"}, {"n": 67, "q": "Look at the graphic. Which laptop does the woman recommend?", "opts": ["H88", "C34", "F56", "X12"], "ans": 3, "ko": "시각 자료를 보시오. 여자는 어느 노트북 컴퓨터를 권하는가?"}], "script": [{"sp": "M", "en": "Pardon me. I'd like to buy my nephew a laptop. He's going to college soon, and he'll need one to write papers.", "ko": "실례합니다. 저는 제 조카에게 노트북 컴퓨터를 사주고 싶은데요. 그가 곧 대학교에 들어갈 거라서, 과제를 작성하기 위해 하나가 필요할 거예요."}, {"sp": "W", "en": "Sure thing. Are there any particular features you have in mind?", "ko": "물론이죠. 생각하고 계신 특정한 특징들이 있나요?"}, {"sp": "M", "en": "I know he likes to have many windows open at once, so a wider screen would be best. I'm leaning toward the C34, but I'm not certain.", "ko": "그가 동시에 많은 창을 켜놓는 것을 좋아한다고 알고 있어서, 더 넓은 화면이 가장 좋겠네요. 저는 C34로 마음이 기울고 있지만, 잘 모르겠어요."}, {"sp": "W", "en": "While the C34 is a great model, it's intended for video editing. I'm guessing it's more powerful than necessary.", "ko": "C34가 훌륭한 모델이긴 하지만, 그것은 영상 편집을 위해 만들어졌어요. 제 생각에 그것은 필요 이상으로 성능이 좋을 거예요."}, {"sp": "M", "en": "Yeah, good point.", "ko": "네, 좋은 지적이네요."}, {"sp": "W", "en": "However, the device just below that one is the same size. Although less powerful than the C34, it's ideal for running word processing programs. It's also much cheaper.", "ko": "하지만, 그것 바로 밑에 있는 기기는 같은 크기예요. C34보다 성능은 덜하지만, 문서 작성 프로그램을 구동하기에 이상적이에요. 그리고 훨씬 저렴해요."}], "gimg": "hk2_t1_g65.jpg"}, {"start": 68, "part": 3, "intro": "", "graphic": true, "speakers": "호주식 발음 → 미국식 발음", "audio": "Test01_68-70.mp3", "qs": [{"n": 68, "q": "Who most likely are the speakers?", "opts": ["School teachers", "Public relations personnel", "IT specialists", "Media representatives"], "ans": 2, "ko": "화자들은 누구인 것 같은가?"}, {"n": 69, "q": "Look at the graphic. Which office was most recently established?", "opts": ["Easton City", "Lowerville", "New Clemson", "Bloomington"], "ans": 2, "ko": "시각 자료를 보시오. 어느 사무실이 가장 최근에 설립되었는가?"}, {"n": 70, "q": "What do the speakers plan to do?", "opts": ["Encourage some workers to make donations", "Participate in an upcoming event", "Announce goals to their colleagues", "Coordinate activities with an organizer"], "ans": 1, "ko": "화자들은 무엇을 할 계획인가?"}], "script": [{"sp": "M", "en": "Charlotte, did you hear that our IT company will be hosting a volunteer day? Management is hoping it'll attract some positive media attention, and all of the technicians are encouraged to participate. I'm really looking forward to it.", "ko": "Charlotte, 우리 IT 회사가 자원봉사의 날을 주최할 거라는 걸 들었어요? 경영진은 이것이 긍정적인 언론의 관심을 끌어모으기를 바라고 있고, 모든 기술자들은 참여하도록 권장돼요. 저는 이것을 매우 기대하고 있어요."}, {"sp": "W", "en": "Yeah, me too. I guess we'll be tutoring students at local schools.", "ko": "네, 저도요. 우리는 지역 학교들에서 학생들을 가르칠 것 같아요."}, {"sp": "M", "en": "It's a great idea, but I'm a bit surprised by some of the goals. Uh, 20 people from our newest office are expected to take part, but there are only 30 employees.", "ko": "이건 좋은 아이디어지만, 일부 목표에 조금 놀랐어요. 어, 우리의 가장 새로 생긴 사무실에서 스무 명이 참여하도록 기대되는데, 그곳에는 단지 서른 명의 직원밖에 없잖아요."}, {"sp": "W", "en": "I'm sure that office will meet its goal. And I'm going to sign up now. I want to make sure that our branch has enough volunteers.", "ko": "저는 그 사무실이 그곳의 목표를 달성할 거라고 확신해요. 그리고 저도 지금 등록할 거예요. 우리 지점에 충분한 자원봉사자가 있도록 확실히 하고 싶어요."}, {"sp": "M", "en": "Good point. I'll join you.", "ko": "좋은 말씀이네요. 저도 함께할게요."}], "gimg": "hk2_t1_g68.jpg"}, {"start": 71, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test01_71-73.mp3", "qs": [{"n": 71, "q": "Where is the announcement most likely being made?", "opts": ["In a supermarket", "In a restaurant", "In an electronics store", "In an office building"], "ans": 0, "ko": "공지는 어디에서 이뤄지고 있는 것 같은가?"}, {"n": 72, "q": "What are listeners instructed to present to an attendant?", "opts": ["A voucher slip", "A parking pass", "A proof of purchase", "An identification card"], "ans": 2, "ko": "청자들은 안내원에게 무엇을 제시하도록 안내되는가?"}, {"n": 73, "q": "What is mentioned about the parking spaces near the elevators?", "opts": ["They meet government standards.", "They are for small vehicles.", "They are reserved for employees.", "They require a permit to use."], "ans": 3, "ko": "엘리베이터 근처의 주차 공간에 관해 무엇이 언급되는가?"}], "script": [{"sp": "W", "en": "May I have your attention, please? This is just a reminder that, as Greenway customers, you do not have to pay for parking in the grocery store's parking lot, provided you spend at least $20 in the store. When you leave our parking facility, simply show your sales receipts to the attendant at the gate. In addition, please note that the parking spaces beside the elevators on all levels of the facility are reserved for the physically disabled. Individuals wishing to park in these spaces must have a valid government permit clearly displayed in the window of their vehicles.", "ko": "모두 주목해 주시겠습니까? Greenway 고객으로서, 여러분이 이 상점에서 최소 20달러를 쓰신다면 식료품점 주차장에 주차하는 것에 대해 지불할 필요가 없다는 것을 상기시켜드립니다. 저희 주차장을 나가실 때, 그저 입구의 안내원에게 영수증을 보여주십시오. 더불어, 주차장의 모든 층에 있는 엘리베이터 옆의 주차 공간들은 신체적으로 장애가 있는 분들을 위해 지정되어 있다는 점에 유의해주십시오. 이 공간에 주차하기를 원하시는 분들께서는 유효한 정부 허가증을 차량 유리창에 명확하게 내보이셔야 합니다."}]}, {"start": 74, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test01_74-76.mp3", "qs": [{"n": 74, "q": "What is the purpose of the speech?", "opts": ["To give a self-introduction", "To state some goals", "To justify some decisions", "To explain an office policy"], "ans": 0, "ko": "연설의 목적은 무엇인가?"}, {"n": 75, "q": "What does the speaker say she did in the past?", "opts": ["Conducted an assessment", "Started her own company", "Met with administrators", "Worked at a law firm"], "ans": 3, "ko": "화자는 과거에 무엇을 했다고 말하는가?"}, {"n": 76, "q": "Why does the speaker say, \"it might take some time to get used to everything here\"?", "opts": ["To ask for patience", "To show appreciation", "To express confusion", "To apologize for an error"], "ans": 0, "ko": "화자는 왜 \"이곳의 모든 것에 익숙해지는 데 시간이 조금 걸릴 것입니다\"라고 말하는가?"}], "script": [{"sp": "W", "en": "Good morning. Department head Louise Shah has asked me to tell you a little about myself since this is my first day here. Well . . . ah . . . before taking this job as an administrative assistant, I was an intern at the legal office of Patel & Ashwin. This is actually my first experience working at an import-export company, so it might take some time to get used to everything here. Anyway, I'm looking forward to this opportunity and to getting to know you all.", "ko": "좋은 아침입니다. 오늘이 이곳에서의 제 첫날이기 때문에 Louise Shah 부장님이 여러분께 저에 대해 약간 말해줄 것을 요청하셨습니다. 음… 아… 행정 비서로서 취직하기 전에, 저는 Patel & Ashwin의 법률 사무소에서 인턴이었습니다. 이것은 사실 수출입 회사에서 일하는 첫 번째 경험이라서, 이곳의 모든 것에 익숙해지는 데 시간이 조금 걸릴 것입니다. 어쨌든, 저는 이 기회와 여러분 모두를 알아가는 것을 기대하고 있습니다."}]}, {"start": 77, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test01_77-79.mp3", "qs": [{"n": 77, "q": "Who most likely are the listeners?", "opts": ["Festival attendees", "Music school students", "Studio technicians", "Record store staff"], "ans": 0, "ko": "청자들은 누구인 것 같은가?"}, {"n": 78, "q": "According to the speaker, what happened in April?", "opts": ["An event was announced.", "A concert was postponed.", "A band was formed.", "An album was released."], "ans": 3, "ko": "화자에 따르면, 4월에 무슨 일이 일어났는가?"}, {"n": 79, "q": "What does the speaker say about Philip Waterfield?", "opts": ["He plans to record more music.", "He rarely gives live performances.", "He has appeared on television.", "He was given an award."], "ans": 1, "ko": "화자는 Philip Waterfield에 관해 무엇을 말하는가?"}], "script": [{"sp": "M", "en": "How's everyone enjoying the music so far? Um, our next performer is making his second appearance at the Salem Blues Festival. He was here seven years ago—the very first time this event was held—and his performance was one of the festival's highlights. At that time, Philip Waterfield was accompanied by five bandmates, but today he'll be appearing on stage all by himself to promote his record, which came out in April. He doesn't play live much anymore, so this is certainly a special occasion. Ladies and gentlemen, put your hands together for Mr. Waterfield.", "ko": "다들 지금까지 음악을 어떻게 즐기시고 계신가요? 음, 저희의 다음 공연자는 Salem 블루스 축제에 두 번째로 출연합니다. 그는 이 행사가 맨 처음 열렸던 7년 전에 여기 있었고 그의 공연은 축제의 하이라이트 중 하나였습니다. 그때, Philip Waterfield는 다섯 명의 밴드 멤버들과 함께했지만, 오늘 그는 4월에 나온 그의 음반을 홍보하기 위해 혼자 무대에 설 것입니다. 그는 더 이상 라이브 연주를 그다지 하지 않으므로, 이것은 분명 특별한 기회입니다. 신사 숙녀 여러분, Mr. Waterfield를 위해 박수를 보내주십시오."}]}, {"start": 80, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test01_80-82.mp3", "qs": [{"n": 80, "q": "According to the speaker, what does Mr. Vang plan to do on June 14?", "opts": ["Verify an itinerary", "Conclude a business trip", "Depart on a cruise", "Pay a remaining balance"], "ans": 2, "ko": "화자에 따르면, Mr. Vang은 6월 14일에 무엇을 할 계획인가?"}, {"n": 81, "q": "What does the speaker mean when he says, \"Premier cabins include queen-size beds\"?", "opts": ["Inaccurate information was provided.", "A handout is outdated.", "A reservation needs to be changed.", "Larger accommodations were added."], "ans": 2, "ko": "화자는 \"최상의 객실이 퀸사이즈 침대들을 포함합니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 82, "q": "What was included in a brochure?", "opts": ["Some photographs", "A price list", "Some coupons", "A phone number"], "ans": 0, "ko": "책자에는 무엇이 포함되었는가?"}], "script": [{"sp": "M", "en": "This message is for Blong Vang in response to his recent inquiry regarding his reservation with StarQuest Voyages. Mr. Vang, our records indicate that there might be a problem with the cruise you booked for June 14 to 21. You asked for a Standard cabin, which includes a twin-size bed. However, in the \"special request\" section, you left a note saying that you require a queen-size mattress. Well, Premier cabins include queen-size beds. Images of these accommodations are included in the digital brochure e-mailed to you last week. If this cabin type is satisfactory, please let us know as soon as possible so that your booking and billing statement can be updated.", "ko": "이 메시지는 StarQuest Voyages사와의 예약에 관한 최근 문의에 대한 응답으로 Blong Vang을 위한 것입니다. Mr. Vang, 저희 기록은 귀하께서 6월 14일부터 21일까지로 예약하신 유람선 여행에 대해 문제가 있을 수 있음을 보여줍니다. 귀하께서는 트윈사이즈 침대를 포함하는 일반 객실을 요청하셨습니다. 하지만, \"특별 요청\" 부분에, 귀하께서 퀸사이즈의 매트리스가 필요하다는 메모를 남기셨습니다. 음, 최상의 객실이 퀸사이즈 침대들을 포함합니다. 이 숙소들의 사진들은 지난주에 귀하께 이메일로 보내드린 디지털 책자에 포함되어 있습니다. 이 객실 유형이 만족스러우시다면, 귀하의 예약과 대금 청구서가 업데이트될 수 있도록 가능한 한 빨리 저희에게 알려주십시오."}]}, {"start": 83, "part": 4, "intro": "", "graphic": false, "speakers": "미국식 발음", "audio": "Test01_83-85.mp3", "qs": [{"n": 83, "q": "What problem does the speaker mention?", "opts": ["A venue has been overbooked.", "Some schedules were not updated.", "Some equipment is not working.", "A speaker cannot attend an event."], "ans": 2, "ko": "화자는 무슨 문제를 언급하는가?"}, {"n": 84, "q": "Who is Shawn Murray?", "opts": ["A government official", "A convention organizer", "A company founder", "A television celebrity"], "ans": 3, "ko": "Shawn Murray는 누구인가?"}, {"n": 85, "q": "What does the speaker suggest?", "opts": ["Waiting for another announcement", "Going to a ballroom early", "Watching a short video clip", "Buying some merchandise"], "ans": 1, "ko": "화자는 무엇을 제안하는가?"}], "script": [{"sp": "M", "en": "Attention, please. Due to technical difficulties with our sound system, there's going to be a change to today's main event at the Recreational Fishing Expo. Shawn Murray, the host of the television show Catch and Release, will still appear at the scheduled time of 2:30 P.M. However, his talk on the impact of technology on amateur fishing will be taking place in the ballroom rather than the auditorium. If you want to get a seat, you may want to head to the ballroom 10 or 15 minutes beforehand. Otherwise, there should be plenty of standing room. Thanks for your understanding.", "ko": "주목해 주시기 바랍니다. 저희 음향 시스템의 기술적 장애로 인해, Recreational 낚시 박람회에서의 오늘의 주요 행사에 변동이 있을 것입니다. 텔레비전 쇼 Catch and Release의 진행자인 Shawn Murray는 예정된 시간인 오후 2시 30분에 여전히 등장할 것입니다. 하지만, 아마추어 낚시에 대한 기술의 영향에 관한 그의 강연은 강당이 아닌 연회장에서 열릴 것입니다. 자리를 잡고 싶으시면, 연회장으로 10분 또는 15분 전에 미리 가실 수 있습니다. 그렇지 않으면, 서 있을 수 있는 공간이 충분히 있습니다. 이해해 주셔서 감사합니다."}]}, {"start": 86, "part": 4, "intro": "", "graphic": false, "speakers": "호주식 발음", "audio": "Test01_86-88.mp3", "qs": [{"n": 86, "q": "What does the speaker say listeners can do?", "opts": ["Choose an instructor", "Reserve a facility", "Rent some skates", "Use a coupon"], "ans": 2, "ko": "화자는 청자들이 무엇을 할 수 있다고 말하는가?"}, {"n": 87, "q": "According to the speaker, what do some people qualify for?", "opts": ["Training lessons", "Free admission", "Complimentary gear", "Annual passes"], "ans": 1, "ko": "화자에 따르면, 일부 사람들은 어떤 자격을 얻는가?"}, {"n": 88, "q": "Why should listeners dial one?", "opts": ["To hear about different rates", "To reserve a storage locker", "To learn about a schedule", "To replay a message"], "ans": 2, "ko": "청자들은 왜 1번을 눌러야 하는가?"}], "script": [{"sp": "M", "en": "You've reached Enderby Ice Rink after regular business hours. If you'd like to use our facility for ice skating, we are open to the public daily between 1 P.M. and 4 P.M. If you don't have your own skates, you can pay $5 an hour to use a pair. Those under the age of 12 can enter at no charge. To hear when the high school hockey matches will be held at our facility throughout the month, please press one now. Otherwise, have a pleasant day.", "ko": "귀하는 정규 영업시간 이후에 Enderby 아이스 링크장에 연락하셨습니다. 만약 여러분이 아이스 스케이팅을 위해 저희의 시설을 이용하고 싶으시면, 저희는 매일 오후 1시부터 오후 4시까지 대중에게 개방하고 있습니다. 귀하가 본인의 스케이트를 갖고 있지 않으면, 한 켤레를 이용하는 데 시간당 5달러를 지불하시면 됩니다. 12세 이하는 무료로 입장할 수 있습니다. 이번 달 동안 저희 시설에서 고등학교 하키 경기들이 언제 열리는지 듣고 싶으시면, 지금 1번을 눌러주세요. 그렇지 않으면, 행복한 하루 보내세요."}]}, {"start": 89, "part": 4, "intro": "", "graphic": false, "speakers": "영국식 발음", "audio": "Test01_89-91.mp3", "qs": [{"n": 89, "q": "What is the report mainly about?", "opts": ["A closure of a station entrance", "An accident along a roadway", "An interruption to a service", "A delay to a construction project"], "ans": 2, "ko": "보도는 주로 무엇에 관한 것인가?"}, {"n": 90, "q": "What does the speaker mean when she says, \"Technicians have been sent to the location\"?", "opts": ["A road will be closed temporarily.", "Some repairs are being made.", "A resident made a request.", "Some workers need assistance."], "ans": 1, "ko": "화자는 \"기술자들이 그 장소에 보내졌습니다\"라고 말할 때 무엇을 의도하는가?"}, {"n": 91, "q": "What will listeners hear next?", "opts": ["An update about the weather", "An interview with a politician", "A report on business", "A broadcast from a fair"], "ans": 2, "ko": "청자들은 다음에 무엇을 들을 것인가?"}], "script": [{"sp": "W", "en": "People commuting on the Calgary subway system this morning have been dealing with delays ever since a train broke down between Bowness Station and Edgemont Station. For over 30 minutes now, trains have not been able to run on the Blue Line. According to the city transportation authority, an electrical failure is to blame for the situation. Technicians have been sent to the location, and we are hoping to get things back to normal soon. Now let's turn to Laura Goodman for a morning business news update.", "ko": "오늘 아침 Calgary 지하철로 통근하는 사람들이 Bowness역과 Edgemont역 사이에서 열차가 고장 난 이후로 지연을 겪고 있습니다. 지금 30분이 넘도록, 열차들은 청색 노선에서 운행하지 못하고 있습니다. 시 교통 당국에 따르면, 정전이 이 상황의 원인입니다. 기술자들이 그 장소에 보내졌으며, 저희는 상황이 곧 정상으로 되돌아가길 바라고 있습니다. 이제 아침 경제 최신 뉴스를 위해 Laura Goodman에게 돌아갑시다."}]}, {"start": 92, "part": 4, "intro": "", "graphic": false, "speakers": "캐나다식 발음", "audio": "Test01_92-94.mp3", "qs": [{"n": 92, "q": "Where are the listeners?", "opts": ["In a living room", "In a bedroom", "In a kitchen", "In a private office"], "ans": 3, "ko": "청자들은 어디에 있는가?"}, {"n": 93, "q": "According to the speaker, what is famous in the house?", "opts": ["Some artwork", "Some furniture", "Some book collections", "Some room designs"], "ans": 1, "ko": "화자에 따르면, 무엇이 이 집에서 유명한가?"}, {"n": 94, "q": "What does the speaker suggest?", "opts": ["Walking around a property", "Reading a display board", "Heading toward an exit", "Looking at some papers"], "ans": 3, "ko": "화자는 무엇을 제안하는가?"}], "script": [{"sp": "M", "en": "OK, everyone, please gather around. This room marks the final portion of your tour of author Leo Edmund's house. As you can see, this was his personal office, and he completed a fair amount of his writing here. As with the living room, bedrooms, and dining room, this is a very modest space considering Mr. Edmund's wealth. The only exception is the fine leather armchairs, which are actually quite famous. They were gifted to Mr. Edmund by King Ferdinand in 1877. Now, on the desk under some protective glass, you'll notice a few pages from Mr. Edmund's journal. I suggest taking a look at them.", "ko": "자, 여러분, 다들 모여주세요. 이 방은 작가 Leo Edmund 가옥 투어의 마지막 부분입니다. 보시다시피, 이곳은 그의 개인 사무실이었고, 그는 그의 저술의 상당한 양을 이곳에서 완성했습니다. 거실, 침실들, 그리고 식당과 마찬가지로, 이곳은 Mr. Edmund의 부를 고려했을 때 굉장히 검소한 공간입니다. 한 가지 예외는 이 질 좋은 가죽 안락의자들인데, 이것들은 실제로 꽤 유명합니다. 이것들은 1877년에 Ferdinand 왕에 의해 Mr. Edmund에게 선물로 주어졌습니다. 자, 책상 위의 보호 유리 아래에, 여러분들은 Mr. Edmund의 일기 중의 몇 장을 발견하실 것입니다. 그것들을 한번 보시기를 제안드립니다."}]}, {"start": 95, "part": 4, "intro": "", "graphic": true, "speakers": "미국식 발음", "audio": "Test01_95-97.mp3", "qs": [{"n": 95, "q": "Why will the speaker be late to an event?", "opts": ["A relative needs a ride.", "Some ingredients have to be picked up.", "A friend asked for help moving.", "Some banners must be made."], "ans": 0, "ko": "화자는 행사에 왜 늦을 것인가?"}, {"n": 96, "q": "According to the speaker, what will take about half an hour?", "opts": ["Making some snacks", "Putting away some supplies", "Decorating a space", "Getting to a destination"], "ans": 2, "ko": "화자에 따르면, 무엇이 30분 정도 걸릴 것인가?"}, {"n": 97, "q": "Look at the graphic. Which amount should be modified?", "opts": ["32 milliliters", "24 milliliters", "16 milliliters", "2 cups"], "ans": 1, "ko": "시각 자료를 보시오. 어느 양이 변경되어야 하는가?"}], "script": [{"sp": "W", "en": "Samuel, it's Clarisa. My grandfather asked me to drive him to a doctor's appointment in the late afternoon. So I'm not going to be at Andrea's house early enough tomorrow to help you prepare for her birthday party. Fortunately, hanging decorations in the living room shouldn't take more than half an hour. As for the drink I was going to make, Andrea has a copy of the recipe. Only, I use 30 milliliters of pineapple juice and also add cubed watermelon. I suggest doing the same. It really improves the flavor. Just call me if you have any questions. Otherwise, I'll see you tomorrow.", "ko": "Samuel, 저 Clarisa예요. 저희 할아버지께서 저에게 오후 늦게 진료 예약에 데려다 달라고 하셨어요. 그래서 Andrea의 생일 파티를 위해 당신이 준비하는 것을 도울 수 있을 정도로 내일 일찍 그녀의 집에 가지 못할 거예요. 다행히도, 거실에 장식들을 다는 것은 30분 이상 걸리지 않을 거예요. 제가 만들려고 했던 음료수에 관해서는, Andrea가 요리법의 복사본을 가지고 있어요. 다만, 저는 30밀리리터의 파인애플 주스를 사용하고, 네모로 썬 수박도 추가해요. 저는 똑같이 하는 걸 추천해요. 그건 정말 맛을 향상시켜줘요. 질문 있으시면 저한테 전화해 주세요. 그렇지 않으면, 내일 봐요."}, {"sp": "W", "en": "Fruit Punch\n32 milliliters of orange juice\n24 milliliters of pineapple juice\n16 milliliters of tonic water\n2 cups of sliced strawberries\n1 cup of sliced kiwi", "ko": "화채\n오렌지 주스 32밀리리터\n파인애플 주스 24밀리리터\n탄산수 16밀리리터\n딸기 조각 두 컵\n키위 조각 한 컵"}], "gimg": "hk2_t1_g95.jpg"}, {"start": 98, "part": 4, "intro": "", "graphic": true, "speakers": "호주식 발음", "audio": "Test01_98-100.mp3", "qs": [{"n": 98, "q": "What is the speaker mainly discussing?", "opts": ["A celebrity visit", "A fund-raising event", "A gallery opening", "A special exhibition"], "ans": 3, "ko": "화자는 주로 무엇에 관해 이야기하고 있는가?"}, {"n": 99, "q": "Look at the graphic. Which piece has yet to be delivered?", "opts": ["Wall with Flowers", "Daylight and More", "Tower Heights", "Reaching for the Sky"], "ans": 1, "ko": "시각 자료를 보시오. 어떤 작품이 아직 전달되지 않았는가?"}, {"n": 100, "q": "What will probably happen this afternoon?", "opts": ["Some paintings will be sold.", "Some tickets will be given away.", "A notice will be posted online.", "A guest will give a short talk."], "ans": 2, "ko": "오늘 오후에 무슨 일이 일어날 것 같은가?"}], "script": [{"sp": "M", "en": "Next Sunday is our art gallery's 20th anniversary, and I want to celebrate this milestone by honoring artists who have been crucial to our success along the way. That's why we'll be hosting a temporary exhibit that day. It'll feature pieces from the first people who showed their work here. I've already coordinated with the artists, and aside from Lola Hays's piece, all of their work has been delivered to our facility, including paintings and sculptures by Mark Rubin and others. I, uh, plan to put up an announcement about the event on our Web site this afternoon. I'm hoping for a large turnout.", "ko": "다음 주 일요일은 우리 미술관의 20주년 기념일이며, 저는 그 과정에서 우리의 성공에 결정적이었던 예술가들에게 경의를 표하며 이 중요한 시점을 기념하고 싶습니다. 그것이 우리가 그날 임시 전시회를 주최하게 될 이유입니다. 이것은 이곳에서 작품들을 선보인 첫 번째 사람들의 작품들을 특별히 포함할 것입니다. 저는 이미 그 예술가들과 협력해 왔으며, Lola Hays의 작품을 제외하고, Mark Rubin과 다른 사람들의 그림과 조각들을 포함한 그들의 모든 작품들이 우리 시설에 전달되었습니다. 저는, 어, 오늘 오후 우리 웹사이트에 이 행사에 대한 소식을 게시할 계획입니다. 저는 많은 수의 참여자들을 기대하고 있습니다."}, {"sp": "M", "en": "Artist / Title of Work\nMark Rubin / Wall with Flowers\nLola Hays / Daylight and More\nKen Hamilton / Tower Heights\nSandy Meyer / Reaching for the Sky", "ko": "예술가 / 작품 제목\nMark Rubin / Wall with Flowers\nLola Hays / Daylight and More\nKen Hamilton / Tower Heights\nSandy Meyer / Reaching for the Sky"}], "gimg": "hk2_t1_g98.jpg"}]};
